SELECT labor_type
FROM labor_costs
WHERE date = '2023-06-01';

SELECT season_id, total_cost, created_at
FROM production_costs
WHERE season_id = 1;

SELECT average_cost
FROM production_analysis
WHERE season_id = 1;

SELECT SUM(total_cost) AS total_variable_cost
FROM production_costs
WHERE cost_type = 'Variable Cost';

SELECT SUM(total_cost) AS total_season_cost
FROM production_costs
WHERE season_id = 1;

SELECT COUNT(*) AS labor_cost_count
FROM labor_costs
WHERE labor_type = 'Bullock Labor';

SELECT SUM(subtotal) AS total_variable_cost
FROM variable_costs
WHERE cost_id = 1;

SELECT SUM(subtotal) AS total_machinery_cost
FROM machinery_costs
WHERE date BETWEEN '2023-06-01' AND '2023-08-31';

SELECT analysis_id 
FROM production_analysis 
ORDER BY analysis_id;
